                const newCost = currentCost + (ni + 1) * (nj + 1);

                if (dp[ni][nj][newStep] === undefined || newCost < dp[ni][nj][newStep]) {
                    dp[ni][nj][newStep] = newCost;
                    queue.push([ni, nj, newStep]);
                }
            }
        } else { // even step: wait
            const newStep = step + 1;
            const newCost = currentCost + waitCost[i][j];

            if (dp[i][j][newStep] === undefined || newCost < dp[i][j][newStep]) {
                dp[i][j][newStep] = newCost;
                queue.push([i, j, newStep]);
            }
        }
    }

    let minCost = Infinity;
    const target = dp[m - 1][n - 1];
    for (const step in target) {
        if (target[step] < minCost) {
            minCost = target[step];
        }
    }
    return minCost;
}

